// Build all 4 email HTML payloads from the webhook payload.
// Input: $input.item.json.body = { id, email, scores, verdict, weakest_key, ... }
// Output: an item with: email, subject_*, html_*, verdict, weakest_title, etc.

const body = $input.item.json.body || {};
const { id, email, scores = {}, verdict, weakest } = body;

// Determine weakest precondition (lowest scoring) — fallback if absent
const PRECONDITION_KEYS = ['structured_input', 'decision_logic', 'narrow_scope', 'human_loop'];
let weakestKey = (Array.isArray(weakest) && weakest[0]) || body.weakest_key;
if (!weakestKey) {
  let lowest = 5;
  for (const k of PRECONDITION_KEYS) {
    const v = Number(scores[k] ?? 5);
    if (v < lowest) { lowest = v; weakestKey = k; }
  }
}

const PRECONDITION_TITLES = {
  structured_input: 'Reliable input pipeline',
  decision_logic: 'Documentable decision logic',
  narrow_scope: 'Narrow initial scope',
  human_loop: 'Human-in-the-loop by design',
};

const ROADMAP_SLUGS = {
  structured_input: 'reliable-input-pipeline',
  decision_logic: 'documentable-decision-logic',
  narrow_scope: 'narrow-initial-scope',
  human_loop: 'human-in-the-loop',
};

const weakestTitle = PRECONDITION_TITLES[weakestKey] || 'one of the four preconditions';
const weakestTitleLower = weakestTitle.toLowerCase();
const roadmapSlug = ROADMAP_SLUGS[weakestKey] || 'reliable-input-pipeline';
const total = (scores.structured_input || 0) + (scores.decision_logic || 0) + (scores.narrow_scope || 0) + (scores.human_loop || 0);

const SITE = 'https://ivanmanfredi.com';
const roadmapUrl = `${SITE}/scorecard/roadmap/${roadmapSlug}`;
const resultUrl = `${SITE}/scorecard/result/${id}`;
const blueprintUrl = `${SITE}/assessment`;
const discoveryUrl = `${SITE}/start`;
const unsubscribeUrl = `mailto:hello@ivanmanfredi.com?subject=Unsubscribe%20${id}&body=I'd%20like%20to%20stop%20receiving%20these%20emails.`;

const verdictLabel =
  verdict === 'agent_ready' ? 'Agent-Ready' :
  verdict === 'close' ? 'Close' :
  'Foundation first';

const verdictOneLiner =
  verdict === 'agent_ready'
    ? 'You meet the four preconditions every AI deployment needs before it ships. The infrastructure is there — what\'s missing is sequencing.'
    : verdict === 'close'
    ? 'You\'re one or two preconditions short of being deployment-ready. The gaps aren\'t fatal, but they will block the build until you close them.'
    : 'The preconditions aren\'t in place yet. That\'s not a problem — it just means the work to do first is ops work, not AI work. Reverse the order and the rest gets easier.';

// Per-precondition snippets (Email 2 + Email 3)
const snippets = {
  structured_input: {
    failure: `A founder I worked with last year had a lead-qualification AI that kept misclassifying enterprise leads as SMB. They tuned the prompt for two weeks. Tried three different models. Same result.<br><br>The actual problem: the source data the AI was reading lived in four places — HubSpot, a Notion table their SDR maintained by hand, an Apollo enrichment that fired sometimes, and a Calendly intake form. Each source had a slightly different idea of "company size." When the AI saw conflicting signals, it defaulted to the smallest number, which made every enterprise lead look like a 50-person SMB.<br><br>Fixing the prompt wouldn\'t have helped. The input pipeline was incoherent.`,
    fix: `<ol><li><strong>Pick one canonical source per data point.</strong> Pick the one that\'s most consistently maintained, not the one that\'s most "complete." A 70%-coverage source that\'s reliably current beats a 95%-coverage source that\'s six months stale.</li><li><strong>Make extraction explicit.</strong> If your canonical source is a doc or chat history, that\'s fine — but write the extraction step. Pretending the AI can "just read" unstructured stuff is the most expensive shortcut in this space.</li><li><strong>Test the pipeline before you test the model.</strong> If the same query gives the same answer twice in a row across a week, you\'re ready. If it doesn\'t, fix that first.</li></ol>`,
  },
  decision_logic: {
    failure: `A consulting firm I worked with had a senior associate who triaged inbound RFPs better than anyone else. They wanted to encode her judgment so the rest of the team could move faster.<br><br>Six weeks in, the AI was getting roughly half the calls right. The associate would look at an RFP and say "no, this one\'s actually a fit, you missed the signal that they mentioned a deadline." The team would update the prompt. Next week, a different signal got missed.<br><br>What was actually happening: she had eighteen heuristics in her head, layered, with weights that shifted based on context. She wasn\'t being unhelpful — she genuinely couldn\'t tell us all of them. We spent two weeks shadowing her with a transcription tool. That document — not the prompt — was what made it work.`,
    fix: `<ol><li><strong>Shadow your best operator on the actual work for a week.</strong> Record what they do, ask them to narrate why. The thing you\'re encoding isn\'t their conscious decisions — it\'s the unconscious ones.</li><li><strong>Write the heuristics as if-then rules first, weights second.</strong> Resist starting with weights. The hard part is naming the rules.</li><li><strong>Test the doc before you test the model.</strong> Hand the doc to someone else on the team and have them make ten decisions using only the doc. If they get six right, the doc is ready for an AI.</li></ol>`,
  },
  narrow_scope: {
    failure: `A SaaS founder hired me to help "automate ops with AI." We mapped what that meant. The list had nineteen workflows on it. Lead routing, onboarding emails, support triage, invoice reconciliation, all of it.<br><br>I asked which one was the bottleneck. He couldn\'t pick. They all seemed important. We agreed to start with one — support triage — and the build shipped in four weeks. It saved the team about twelve hours a week. He immediately wanted to roll the same approach across the other eighteen.<br><br>The next eighteen weren\'t the same shape. Lead routing required CRM integrations they didn\'t have. Invoice reconciliation touched a finance system with brittle exports. None of those problems showed up until we tried. The narrow scope wasn\'t a constraint — it was the reason the first build worked.`,
    fix: `<ol><li><strong>Pick one workflow. Define it end-to-end.</strong> What\'s the input? What\'s the output? Who\'s the user? What does failure look like? If you can\'t answer in five minutes, the scope isn\'t narrow yet.</li><li><strong>Refuse to widen until the first one is in production for 30 days.</strong> Not "demo\'d" — running, with humans not babying it. The 30 days is where you find out which assumptions were wrong.</li><li><strong>Treat each new workflow as a separate scope decision.</strong> Don\'t assume the second is just like the first. Skipping that surfacing on workflow #2 erases the win from #1.</li></ol>`,
  },
  human_loop: {
    failure: `An agency I worked with had an AI summarizer for client weekly reports. The team loved it. Saved each PM about an hour a week.<br><br>Six months in, a major client churned. Reason given: "the reports stopped reflecting what was actually happening on our account."<br><br>The AI summaries were good 90% of the time. Nobody read them carefully because they were usually fine. The 10% of weeks where the AI missed nuance, the wrong summary went out and the PM didn\'t catch it. Over six months, the cumulative drift broke the relationship. The summarizer wasn\'t bad. The review step was missing. "PM glances at it" is not a review step — it\'s a hope.`,
    fix: `<ol><li><strong>Name the human.</strong> Not "the team" — a specific person, by role, who owns review. If review is everyone\'s job, it\'s nobody\'s job.</li><li><strong>Design the review path before the AI ships.</strong> The output needs to land somewhere the reviewer is already looking — their inbox, their Slack, their queue. Adding a new dashboard is how reviews stop happening.</li><li><strong>Plan the failure path.</strong> What happens when the reviewer flags something wrong? "Reviewer fixes it manually and we hope it doesn\'t happen again" is the failure mode of every AI ops project that quietly stops working.</li></ol>`,
  },
};

const snippet = snippets[weakestKey] || snippets.structured_input;

// Common email shell
const shell = (preheader, bodyHtml) => `<!DOCTYPE html>
<html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><style>body{margin:0;padding:0;background:#F7F4EF;color:#1A1A1A;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:16px;line-height:1.6}a{color:#4C6E3D}</style></head>
<body><span style="display:none;font-size:0;line-height:0;max-height:0;max-width:0;opacity:0;overflow:hidden">${preheader}</span>
<div style="max-width:560px;margin:32px auto;padding:32px 24px;background:#F7F4EF">
<p style="font-family:'DM Serif Display',Georgia,serif;font-style:italic;font-size:28px;margin:0 0 28px 0;color:#1A1A1A">Manfredi</p>
${bodyHtml}
<hr style="border:none;border-top:1px solid rgba(26,26,26,0.15);margin:36px 0 14px 0" />
<p style="font-size:11px;color:#888;margin:0">Manfredi · <a href="${SITE}" style="color:#888">ivanmanfredi.com</a> · <a href="${unsubscribeUrl}" style="color:#888">Unsubscribe</a></p>
</div></body></html>`;

// === EMAIL 1 — Immediate ===
const subject1 = `Your Agent-Ready verdict (${total}/20)`;
const preheader1 = 'Plus your 30-day roadmap.';
const body1 = `<p>Hey there,</p>
<p>You finished the scorecard. Your verdict is <strong>${verdictLabel}</strong>, scored ${total}/20.</p>
<p style="border-left:2px solid #4C6E3D;padding-left:14px;color:#4A4A48;font-style:italic">${verdictOneLiner}</p>
<p>The weakest link in your stack right now is <strong>${weakestTitle}</strong>. That\'s the precondition I\'d start with — not because the others don\'t matter, but because most teams fix three out of four and then stall on the one they didn\'t.</p>
<p>I put together a short roadmap that walks through how to tighten that specific precondition over the next 30 days. No theory, no jargon. Just the order to do things in.</p>
<p style="text-align:center;margin:32px 0"><a href="${roadmapUrl}" style="background:#4C6E3D;color:#fff;padding:14px 22px;text-decoration:none;font-weight:600">Read your 30-day roadmap →</a></p>
<p>Your scorecard result lives at this URL: <a href="${resultUrl}">${resultUrl}</a></p>
<p>I\'ll send a couple more notes over the next ten days. After that, I\'ll go quiet unless you write back.</p>
<p>— Iván</p>`;

// === EMAIL 2 — Day 3 ===
const subject2 = `When ${weakestTitleLower} goes wrong`;
const preheader2 = 'A short story from a recent build.';
const body2 = `<p>Hey,</p>
<p>Quick follow-up on your scorecard. You scored lowest on <strong>${weakestTitle}</strong>, so let me show you what that actually looks like when it breaks in production.</p>
<p>${snippet.failure}</p>
<p>The pattern is always the same. The team thinks the AI is the problem. The AI is fine — it\'s working with what it was given. The thing underneath it isn\'t ready, and the failure shows up as "the AI isn\'t accurate enough."</p>
<p>Most of the work I do isn\'t AI work. It\'s tightening the ${weakestTitleLower} so the AI can actually do its job.</p>
<p>Next email I\'ll walk through the specific moves that fix this.</p>
<p>— Iván</p>`;

// === EMAIL 3 — Day 7 ===
const subject3 = `How to tighten ${weakestTitleLower}`;
const preheader3 = 'Three moves, in order.';
const body3 = `<p>Hey,</p>
<p>Here\'s the order I\'d fix <strong>${weakestTitle}</strong> in. Not the only way — just the one that\'s worked across the last twenty-something builds.</p>
${snippet.fix}
<p>That\'s the full sequence. None of it requires AI. Most of it doesn\'t require code. It\'s process work, which is why most founders skip it — it doesn\'t feel like the exciting part.</p>
<p>If you do this work first, the AI build that comes next takes a fraction of the time and actually holds. If you skip it, the AI build will look like it works in the demo and quietly drift in production.</p>
<p>If you want help mapping this for your specific operation, that\'s what the <strong>Agent-Ready Blueprint</strong> does. One week. You leave with the sequenced plan.</p>
<p style="text-align:center;margin:32px 0"><a href="${blueprintUrl}" style="background:#4C6E3D;color:#fff;padding:14px 22px;text-decoration:none;font-weight:600">Build your Blueprint →</a></p>
<p>— Iván</p>`;

// === EMAIL 4-A — Day 10 (Agent-Ready / Close) ===
const subject4a = 'Last note from me';
const preheader4a = 'Then I\'ll get out of your inbox.';
const body4a = `<p>Hey,</p>
<p>Last note. You scored ${verdictLabel} — meaning you\'re either there or one or two preconditions away.</p>
<p>When teams in your spot pay for the <strong>Agent-Ready Blueprint</strong>, here\'s what they get back:</p>
<ul><li>A scorecard against all four preconditions, with specific gaps named</li><li>Your <strong>90-Day AI Rollout Plan</strong> — sequenced builds for the next 90 and 180 days</li><li>Costed gap analysis with a dollar number on every gap</li><li>Decision logic for the first project, ready to hand to any builder</li><li>A 60-minute live walkthrough of the findings</li></ul>
<p>It\'s $2,500. If you move forward with any follow-on engagement, the full $2,500 is credited back. If I tell you to wait and fix the foundation first, that recommendation is the deliverable.</p>
<p>If your operation clears the four conditions, AI becomes a force multiplier. If it doesn\'t, you\'re funding demos that never ship. The Blueprint is one week of finding out which one you are.</p>
<p style="text-align:center;margin:32px 0"><a href="${blueprintUrl}" style="background:#4C6E3D;color:#fff;padding:14px 22px;text-decoration:none;font-weight:600">Build your Blueprint →</a></p>
<p>If now isn\'t the right time, no follow-up. The roadmap is yours to keep.</p>
<p>— Iván</p>`;

// === EMAIL 4-B — Day 10 (Foundation) ===
const subject4b = 'Last note from me';
const preheader4b = 'Then I\'ll get out of your inbox.';
const body4b = `<p>Hey,</p>
<p>Last note. You scored ${verdictLabel} — meaning the four preconditions aren\'t quite in place yet, and AI work right now would be premature.</p>
<p>That\'s the most useful thing the scorecard can tell someone. Most founders find this out by spending six months and $40k on a build that doesn\'t hold.</p>
<p>If you want to talk through what to fix first, I do free 30-minute discovery calls. No pitch. We figure out the right path and what — if anything — I should be involved in. Sometimes the answer is "you don\'t need me yet, here\'s what to do for the next quarter." That\'s a fine outcome.</p>
<p style="text-align:center;margin:32px 0"><a href="${discoveryUrl}" style="background:#4C6E3D;color:#fff;padding:14px 22px;text-decoration:none;font-weight:600">Book a 30-min call →</a></p>
<p>If now isn\'t the right time, no follow-up. The roadmap is yours to keep.</p>
<p>— Iván</p>`;

return {
  json: {
    id,
    email,
    verdict,
    weakest_key: weakestKey,
    weakest_title: weakestTitle,
    total,
    subject1, html1: shell(preheader1, body1),
    subject2, html2: shell(preheader2, body2),
    subject3, html3: shell(preheader3, body3),
    subject4a, html4a: shell(preheader4a, body4a),
    subject4b, html4b: shell(preheader4b, body4b),
  },
};

